class Solution:
    def minSwapsToMakePalindrome(self, s: str) -> int:
        n = len(s)
        dp = [[0] * 26 for _ in range(n)]
        for i in range(n):
            for j in range(26):
                dp[i][j] = 0
        for i in range(n):
            for j in range(26):
                if i == 0 or j == 0:
                    dp[i][j] = 1
                elif s[i-1] == chr(j + 97):
                    dp[i][j] = 1 + dp[i-1][j]
                else:
                    dp[i][j] = max(dp[i-1][j], dp[i][j-1])
        ans = 0
        for i in range(n):
            for j in range(26):
                ans = max(ans, dp[i][j])
        return n - ans

