class Solution {
    public:
        int minSwapsToMakePalindrome(string s) {
            int n = s.size();
            vector<vector<int>> dp(n, vector<int>(26));
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < 26; j++) {
                    dp[i][j] = 0;
                }
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < 26; j++) {
                    if (i == 0 || j == 0) {
                        dp[i][j] = 1;
                    } else if (s[i-1] == char(j + 97)) {
                        dp[i][j] = 1 + dp[i-1][j];
                    } else {
                        dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
                    }
                }
            }
            int ans = 0;
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < 26; j++) {
                    ans = max(ans, dp[i][j]);
                }
            }
            return n - ans;
        }
    };
